// Упрощенная реализация html2canvas для демонстрации
window.html2canvas = function(element, options = {}) {
    return new Promise((resolve, reject) => {
        try {
            // Получаем размеры элемента
            const rect = element.getBoundingClientRect();
            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d');
            
            // Устанавливаем размеры canvas
            const scale = options.scale || 1;
            canvas.width = rect.width * scale;
            canvas.height = rect.height * scale;
            
            // Масштабируем контекст
            ctx.scale(scale, scale);
            
            // Заливаем фон
            ctx.fillStyle = options.backgroundColor || '#ffffff';
            ctx.fillRect(0, 0, rect.width, rect.height);
            
            // Простая реализация: создаем SVG с HTML и конвертируем в canvas
            const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
            svg.setAttribute('width', rect.width);
            svg.setAttribute('height', rect.height);
            
            const foreignObject = document.createElementNS('http://www.w3.org/2000/svg', 'foreignObject');
            foreignObject.setAttribute('width', '100%');
            foreignObject.setAttribute('height', '100%');
            
            // Клонируем элемент
            const clonedElement = element.cloneNode(true);
            
            // Встраиваем стили
            const styles = Array.from(document.styleSheets)
                .map(sheet => {
                    try {
                        return Array.from(sheet.cssRules)
                            .map(rule => rule.cssText)
                            .join('\\n');
                    } catch (e) {
                        return '';
                    }
                })
                .join('\\n');
            
            const styleElement = document.createElement('style');
            styleElement.textContent = styles;
            
            const wrapper = document.createElement('div');
            wrapper.appendChild(styleElement);
            wrapper.appendChild(clonedElement);
            
            foreignObject.appendChild(wrapper);
            svg.appendChild(foreignObject);
            
            // Конвертируем SVG в Data URL
            const svgData = new XMLSerializer().serializeToString(svg);
            const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
            const svgUrl = URL.createObjectURL(svgBlob);
            
            const img = new Image();
            img.onload = function() {
                ctx.drawImage(img, 0, 0);
                URL.revokeObjectURL(svgUrl);
                resolve(canvas);
            };
            
            img.onerror = function() {
                // Fallback: рисуем простую таблицу вручную
                drawSimpleTable(ctx, element, rect.width, rect.height);
                resolve(canvas);
            };
            
            img.src = svgUrl;
            
        } catch (error) {
            reject(error);
        }
    });
};

function drawSimpleTable(ctx, element, width, height) {
    // Простая отрисовка таблицы
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, width, height);
    
    // Заголовок
    ctx.fillStyle = '#1a1a1a';
    ctx.fillRect(0, 0, width, 60);
    
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 18px Inter, Arial, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('Мой прогноз таблицы Премьер-лиги', width / 2, 25);
    
    ctx.font = '14px Inter, Arial, sans-serif';
    ctx.fillText(new Date().toLocaleDateString('ru-RU'), width / 2, 45);
    
    // Строки таблицы
    const items = element.querySelectorAll('.preview-item');
    items.forEach((item, index) => {
        const y = 60 + (index * 35);
        
        // Фон строки
        ctx.fillStyle = index % 2 === 0 ? '#ffffff' : '#f8f9fa';
        ctx.fillRect(0, y, width, 35);
        
        // Номер позиции
        ctx.fillStyle = '#FF6900';
        ctx.font = 'bold 16px Inter, Arial, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(index + 1, 30, y + 22);
        
        // Название клуба
        const clubName = item.querySelector('.preview-name').textContent;
        ctx.fillStyle = '#1a1a1a';
        ctx.font = '14px Inter, Arial, sans-serif';
        ctx.textAlign = 'left';
        ctx.fillText(clubName, 60, y + 22);
        
        // Линия разделителя
        if (index < items.length - 1) {
            ctx.strokeStyle = '#e0e0e0';
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(0, y + 35);
            ctx.lineTo(width, y + 35);
            ctx.stroke();
        }
    });
}



